const items = $input.all();
return items.filter(i => i.json && i.json.ref).map(i => {
  const r = i.json;
  const dep = new Date(r.departure_at);
  const hh = String(dep.getHours()).padStart(2,'0');
  const mm = String(dep.getMinutes()).padStart(2,'0');
  const msg = `Habari ${r.passenger_name}! Ukumbusho: Safari yako ya Bus TZ PAWA kwenda ${r.destination} inaanza saa ${hh}:${mm} leo. Kiti: ${r.seat_number} | Basi: ${r.plate}. Eneo la kupanda: ${r.origin}. Tafadhali fika mapema. Safari njema!`;
  return { json: { phone: r.phone, message: msg } };
});

