const items = $input.all();
return items.filter(i => i.json && i.json.ref).map(i => {
  const r = i.json;
  const url = $env.WEBSITE_URL || 'https://bustzpawa.co.tz';
  const phone = $env.SUPPORT_PHONE || '0800 000 000';
  const msg = `Habari ${r.passenger_name}! Asante kwa kusafiri na Bus TZ PAWA! Wakati wowote unapotaka kusafiri tena, tembelea ${url} au piga ${phone}. Karibu tena - safari yako ijayo inakungoja!`;
  return { json: { phone: r.phone, message: msg } };
});
